+                    self.ip += 1;
+                }
+                Ir3Instruction::Throw { .. } => {
+                    return Err(InterpreterError::Halted);
+                }
+                Ir3Instruction::EnterCatch { dst } => {
+                    self.write_reg(dst, Value::Undefined)?;
+                    self.ip += 1;
+                }
+                Ir3Instruction::EnterFinally => {
+                    self.ip += 1;
+                }
+                Ir3Instruction::EndFinally => {
+                    self.ip += 1;
+                }
             }
         }
     }

